SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, view_count, notice_yn, title, add_id, content, user_name, user_ip, delete_yn, add_date, modify_date, file_count, preview_img, secret_yn, --content_summary, category1, category2, category3, category4, category5, kioskNotice_start_date, kioskNotice_end_date, kiosk_yn, getCodeIdToCodeName(#{homepage_id},#{category1Manage},category1) as category1_name, getCodeIdToCodeName(#{homepage_id},#{category2Manage},category2) as category2_name, getCodeIdToCodeName(#{homepage_id},#{category3Manage},category3) as category3_name, getCodeIdToCodeName(#{homepage_id},#{category4Manage},category4) as category4_name, getCodeIdToCodeName(#{homepage_id},#{category5Manage},category5) as category5_name, file_download_count, user_phone, imsi_v_1, imsi_v_2, imsi_v_3, imsi_v_4, imsi_v_5, imsi_v_1, imsi_v_2, imsi_v_3, imsi_v_4, imsi_v_5, imsi_v_6, imsi_v_7, imsi_v_8, imsi_v_9, imsi_v_10, imsi_v_11, imsi_v_12, TRUNC(TO_CHAR(SYSDATE,'yyyyMMdd')) - TRUNC(TO_CHAR(add_date,'yyyyMMdd')) AS date_gap, ( SELECT COUNT(*) FROM CMS_BOARD_COMMENT a WHERE a.board_idx = CMS_BOARD_T.board_idx AND a.delete_yn = 'N' ) AS comment_count
, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_20, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_21, ( SELECT MOD(TO_NUMBER(REPLACE(homepage_id, 'h', '')),8)+1 FROM CMS_BOARD_MANAGE M WHERE M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_n_1, ( SELECT H.context_path FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_19, ( SELECT MAX(H.menu_idx) FROM CMS_MENU H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx AND H.manage_idx = M.manage_idx AND H.menu_type = 'BOARD' AND H.use_yn = 'Y' ) AS imsi_n_2
FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, view_count, notice_yn, title, add_id, content, user_name, user_ip, delete_yn, add_date, modify_date, file_count, preview_img, secret_yn, file_download_count, --content_summary, category1, category2, category3, category4, category5, imsi_v_1, imsi_v_2, imsi_v_3, imsi_v_4, imsi_v_5, imsi_v_6, imsi_v_7, imsi_v_8, imsi_v_9, imsi_v_10, imsi_v_11, imsi_v_12, user_phone, kioskNotice_start_date, kioskNotice_end_date, kiosk_yn FROM CMS_BOARD WHERE
manage_idx in ( SELECT manage_idx FROM cms_board_manage WHERE
board_type = 'NOTICE'
AND homepage_id = #{homepage_id}
board_type = 'NEWS'
AND homepage_id = #{homepage_id}
)
manage_idx = #{manage_idx}
AND delete_yn = #{delete_yn} AND kiosk_yn = 'Y'
) A START WITH A.parent_idx = 0 CONNECT BY PRIOR A.board_idx = A.parent_idx
ORDER SIBLINGS BY A.add_date DESC
A.add_date DESC, A.board_idx DESC
${pagingBottom} ) CMS_BOARD_T

SELECT CMS_BOARD_T.*, TRUNC(TO_CHAR(SYSDATE,'yyyyMMdd')) - TRUNC(TO_CHAR(add_date,'yyyyMMdd')) AS date_gap, ( SELECT COUNT(*) FROM CMS_BOARD_COMMENT a WHERE a.board_idx = CMS_BOARD_T.board_idx AND a.delete_yn = 'N' ) AS comment_count FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, view_count, notice_yn, title, add_id, content, user_name, user_ip, delete_yn, add_date, modify_date, category1, category2, category3, category4, category5, file_count, preview_img, secret_yn, content_summary, file_download_count, imsi_v_1, imsi_v_2, imsi_v_3, imsi_v_4, imsi_v_5, imsi_v_6, imsi_v_7, imsi_v_8, imsi_v_9, imsi_v_10, imsi_v_11,imsi_v_12,imsi_v_13,imsi_v_14,imsi_v_15, imsi_v_16,imsi_v_17,imsi_v_18,imsi_v_19,imsi_v_20, imsi_v_21,imsi_v_22 FROM CMS_BOARD WHERE manage_idx = #{manage_idx} AND delete_yn = #{delete_yn}
AND imsi_v_1 = #{plan_date}
) A START WITH A.parent_idx = 0 CONNECT BY PRIOR A.board_idx = A.parent_idx ORDER SIBLINGS BY A.group_idx DESC, A.board_idx DESC ${pagingBottom} ) CMS_BOARD_T

SELECT CMS_BOARD_T.*, TRUNC(TO_CHAR(SYSDATE,'yyyyMMdd')) - TRUNC(TO_CHAR(add_date,'yyyyMMdd')) AS date_gap, ( SELECT COUNT(*) FROM CMS_BOARD_COMMENT a WHERE a.board_idx = CMS_BOARD_T.board_idx AND a.delete_yn = 'N' ) AS comment_count
, ( SELECT H.homepage_name FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_18, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_20, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_21, ( SELECT MOD(TO_NUMBER(REPLACE(homepage_id, 'h', '')),8)+1 FROM CMS_BOARD_MANAGE M WHERE M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_n_1, ( SELECT H.context_path FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_19, ( SELECT MAX(H.menu_idx) FROM CMS_MENU H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx AND H.manage_idx = M.manage_idx AND H.menu_type = 'BOARD' ) AS imsi_n_2
FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, view_count, notice_yn, title, add_id, content, user_name, user_ip, delete_yn, add_date, modify_date, file_count, preview_img, secret_yn, content_summary, file_download_count, category1, category2, category3, category4, category5, imsi_v_1, case when length(imsi_v_2) = 1 then '0'||imsi_v_2 else imsi_v_2 end imsi_v_2, imsi_v_3, case when length(imsi_v_4) = 1 then '0'||imsi_v_4 else imsi_v_4 end imsi_v_4, imsi_v_5, imsi_v_6, imsi_v_7, imsi_v_8, imsi_v_9, imsi_v_10, imsi_v_11,imsi_v_12,imsi_v_13,imsi_v_14,imsi_v_15, imsi_v_16,imsi_v_17 FROM CMS_BOARD WHERE
manage_idx in ( SELECT manage_idx FROM cms_board_manage WHERE board_type = 'MOVIE'
AND homepage_id = #{homepage_id}
)
manage_idx = #{manage_idx}
AND delete_yn = #{delete_yn} AND imsi_v_1 = #{plan_date}
) A START WITH A.parent_idx = 0 CONNECT BY PRIOR A.board_idx = A.parent_idx ORDER SIBLINGS BY A.group_idx DESC, A.board_idx DESC ${pagingBottom} ) CMS_BOARD_T order by to_date(imsi_v_1, 'YYYY-MM'), to_number(imsi_v_2)

SELECT CMS_BOARD_T.*, TRUNC(TO_CHAR(SYSDATE,'yyyyMMdd')) - TRUNC(TO_CHAR(add_date,'yyyyMMdd')) AS date_gap, ( SELECT COUNT(*) FROM CMS_BOARD_COMMENT a WHERE a.board_idx = CMS_BOARD_T.board_idx AND a.delete_yn = 'N' ) AS comment_count FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, add_date, file_count, file_download_count
