) A START WITH A.parent_idx = 0 CONNECT BY PRIOR A.board_idx = A.parent_idx ORDER SIBLINGS BY A.group_idx DESC, A.board_idx DESC ${pagingBottom} ) CMS_BOARD_T

SELECT CMS_BOARD_T.*, TRUNC(TO_CHAR(SYSDATE,'yyyyMMdd')) - TRUNC(TO_CHAR(add_date,'yyyyMMdd')) AS date_gap, ( SELECT COUNT(*) FROM CMS_BOARD_COMMENT a WHERE a.board_idx = CMS_BOARD_T.board_idx AND a.delete_yn = 'N' ) AS comment_count FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, add_date, file_count, file_download_count
