, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_20, ( SELECT H.homepage_alias FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_21, ( SELECT MOD(TO_NUMBER(REPLACE(homepage_id, 'h', '')),8)+1 FROM CMS_BOARD_MANAGE M WHERE M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_n_1, ( SELECT H.context_path FROM CMS_HOMEPAGE H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx ) AS imsi_v_19, ( SELECT MAX(H.menu_idx) FROM CMS_MENU H, CMS_BOARD_MANAGE M WHERE H.homepage_id = M.homepage_id AND M.manage_idx = CMS_BOARD_T.manage_idx AND H.manage_idx = M.manage_idx AND H.menu_type = 'BOARD' ) AS imsi_n_2
FROM ( ${pagingTop} SELECT A.* FROM ( SELECT manage_idx, board_idx, group_idx, parent_idx, group_depth, view_count, notice_yn, title, add_id, content, user_name, user_ip, delete_yn, add_date, modify_date, file_count, preview_img, secret_yn, content_summary, category1, category2, category3, category4, category5, imsi_v_1, imsi_v_2, imsi_v_3, imsi_v_4, imsi_v_5 FROM CMS_BOARD WHERE
manage_idx in ( SELECT manage_idx FROM cms_board_manage WHERE board_type = 'NOTICE' )
manage_idx = #{manage_idx}
AND delete_yn = #{delete_yn}
) A START WITH A.parent_idx = 0 CONNECT BY PRIOR A.board_idx = A.parent_idx ORDER SIBLINGS BY A.group_idx DESC, A.board_idx DESC ${pagingBottom} ) CMS_BOARD_T

